const generatePrefix = (runNumber, now, prefixData) => {
    let generated = prefixData.current_prefix_config;
    generated = generated.replace("prefix", prefixData.prefix_value);
    generated = generated.replace("suffix", prefixData.suffix_value);
    generated = generated.replace("month", String(now.getMonth() + 1).padStart(2, "0"));
    generated = generated.replace("day", String(now.getDate()).padStart(2, '0'));
    generated = generated.replace("year", now.getFullYear());
    generated = generated.replace("running_number", String(runNumber).padStart(prefixData.padding_zeroes, '0'));
    return generated;
};

const checkUniqueness = async (generatedPrefix, organizationId) => {
    const existingDoc = await db.collection("Customer")
        .where({customer_id: generatedPrefix, organization_id: organizationId})
        .get();
    return existingDoc.data[0] ? false : true;
};

const findUniquePrefix = async (prefixData, organizationId) => {
    const now = new Date();
    let prefixToShow;
    let runningNumber = prefixData.running_number;
    let isUnique = false;
    let maxAttempts = 10;
    let attempts = 0;

    while (!isUnique && attempts < maxAttempts) {
        attempts++;
        prefixToShow = await generatePrefix(runningNumber, now, prefixData);
        isUnique = await checkUniqueness(prefixToShow, organizationId);
        if (!isUnique) {
            runningNumber++;
        }
    }

    if (!isUnique) {
        this.$message.error("Could not generate a unique Customer number after maximum attempts");
    }
    return { prefixToShow, runningNumber };
};

const setPrefix = async (organizationId) => {
    const prefixData = await getPrefixData(organizationId);

    const { prefixToShow } = await findUniquePrefix(prefixData, organizationId);

    this.setData({ 'customer_id': prefixToShow });
}

