    stateName,
    countryName
  ]
  .filter((detail) => detail) 
  .join(
    ([newAddress.address_city, newAddress.address_postal_code, stateName, countryName]
      .filter((detail) => detail)
      .pop() || "").endsWith(",") ? " " : ", "
  );

  const phoneNumber = `+${newAddress.address_phone}${
  newAddress.switch_save_as_default ? ' (default)' : ''
    }`;

  const addressAttention = newAddress.address_attention ? '\nAttention: ' + newAddress.address_attention : ''

